frappe.ui.form.on('Sales Order', {
    onload(frm) {

        frm.set_query('transporter', function() {
        	return {
        		filters: {
        			'is_transporter': 1
        		}
        	}
        });        

    },
	refresh(frm) {
        let fiscal_start = new Date("2026-04-01"); // Start of current fiscal year
        let fiscal_end = new Date("2027-03-31");   // End of current fiscal year
        let order_date = new Date(frm.doc.transaction_date);

        // Disable print button if the date is outside the current fiscal year
        if (order_date < fiscal_start || order_date > fiscal_end) {
            // Remove the Print button            
            // Show a message to inform the user
            frappe.msgprint("This Sales Order is from a previous fiscal year.");
        }
	},
	customer: function(frm) {
        if (frm.doc.customer) {
            // Fetch the default transporter from the customer
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: 'Customer',
                    filters: { 'name': frm.doc.customer },
                    fieldname: 'default_transporter'
                },
                callback: function(response) {
                    if (response.message && response.message.default_transporter) {
                        // Update the 'transporter' field in real-time
                        frm.set_value('transporter', response.message.default_transporter);
                    } else {
                        // If no default transporter, set transporter to null
                        frm.set_value('transporter', null);
                    }
                }
            });
        }
    }


})

