frappe.ui.form.on('Delivery Note', {
    onload: function(frm) {
        // Set initial filter for transaction_date onload
        frm.set_query('sales_order', function() {
            return {
                filters: {
                    "transaction_date": [">", "2024-03-31"]
                }
            };
        });
    },
    customer: function(frm) {
        // Update sales_order filter when customer is selected
        if (frm.doc.customer) {
            var filters = {
                "transaction_date": [">", "2024-03-31"],
                "customer": frm.doc.customer
            };

            frm.set_query('sales_order', function() {
                return {
                    filters: filters
                };
            });
        }
    }
});

frappe.ui.form.on('Stock Entry', {
    printBarcode: function(doc) {
      frappe.run_serially([
        function() {
          return frappe.ui.form.qz_init({silent: true});
        },
        function() {
          return frappe.ui.form.qz_get_printer_list();
        },
        function(printerList) {
          return new Promise(function(resolve, reject) {
            frappe.prompt({
              label: 'Select a printer',
              fieldname: 'printer',
              fieldtype: 'Select',
              options: printerList,
            }, function(values) {
              resolve(values.printer);
            });
          });
        },
        function(selectedPrinter) {
          return frappe.ui.form.qz_connect({silent: true}).then(function() {
            const config = qz.configs.create(selectedPrinter);
            const printData = doc.items.reduce(function(acc, item) {
              if (item.t_warehouse && !item.s_warehouse) {
                acc.push({
                  type: 'raw',
                  format: 'plain',
                //   data: `^XA
                //          ^FO25,0^BY1,2^BCN,50,N,N^FD${item.batch_no}^FS
                //          ^FO20,55^A0N,24,24^FD${item.batch_no}^FS
                //          ^FO20,80^A0N,24,24^FD${item.item_code}^FS
                //          ^FO190,105^A0N,24,24^FD${item.qty}^FS
                //          ^XZ`
                
                    data: `N\nq302\nQ158,24\nJF\nD9\nS2\nB14,12,0,1,2,6,37,B,"${item.batch_no}"\nA14,90,0,3,1,1,N,"${item.item_code}"\nA14,120,0,3,1,1,N,"${item.qty}"\nP1,1\nN\nFF`
          
                });
              }
              return acc;
            }, []);
            if (printData.length) {
              return qz.print(config, printData).then(() => {
                console.log('Barcode printed successfully.');
              }).catch(function (err) {
                console.error(err);
              });
            } else {
              frappe.show_alert({
                message: 'No items to print barcode',
                indicator: 'orange'
              });
            }
          });
        }
      ]);
    },


    refresh: function(frm) {
        
        frm.add_custom_button(__('Print Barcode'), function() {
            frm.events.printBarcode(frm.doc);
        });
    
        if (frm.doc.docstatus <1) {
            frm.add_custom_button(__('Duplicate Row'), function() {
                if (!frm.doc.items) {
                    frappe.msgprint(__('Items table has not been loaded yet. Please try again.'));
                    return;
                }
                frappe.prompt([
                    {fieldtype: 'Int', label: 'Row Number', fieldname: 'row_num',reqd: true},
                    {fieldtype: 'Int', label: 'Number of Duplicates', fieldname: 'n',reqd: true},
                ], function(values) {
                    var row_num = values.row_num;
                    var n = values.n;
                    if (row_num && n) {
                        var row = frm.doc.items[row_num-1];
                        if (row) {
                            for (var i=0; i<n; i++) {
                                var new_row = frm.add_child('items');
                                for (var key in row) {
                                    if (key !== 'idx' && key !== 'name') {
                                        new_row[key] = row[key];
                                    }
                                }
                            }
                            frm.refresh_field('items');
                        } else {
                            frappe.msgprint(__('Invalid Row Number'));
                        }
                    } else {
                        frappe.msgprint(__('Row Number and Number of Duplicates are mandatory'));
                    }
                }, 'Duplicate Row');
            }).addClass('btn-primary');
        }
    }
});

