frappe.ui.form.on('Item', {
    onload: function(frm) {
        loadQZTrayScript(function() {
            console.log('QZ Tray Script loaded');
        });
    },
    refresh: function(frm) {
        if (window.qz && frm.doc.has_variants) {
            frm.add_custom_button(__('Print Variant Labels'), function() {
                print_variants(frm);
            });
        }
    }
});

function loadQZTrayScript(callback) {
    var script = document.createElement('script');
    script.type = 'text/javascript';
    script.src = 'https://cdn.jsdelivr.net/npm/qz-tray@2.2.3/qz-tray.min.js';
    script.onload = callback;
    document.head.appendChild(script);
}

function generate_zpl(variant) {
    return [
        'N',
        'q302',
        'Q158,24',
        'JF',
        'D9',
        'S2',
        `B18,12,0,1,1,3,37,B,"${variant.name}"`,
        `A18,90,0,3,1,2,N,"Rs. ${variant.standard_rate} /- ${variant.price_list}"`,
        'P1,1',
        'N',
        'FF'
    ].join('\n');
}

function selectPrinter(printers) {
    return new Promise((resolve, reject) => {
        let d = new frappe.ui.Dialog({
            title: 'Select Printer',
            fields: [
                {
                    fieldtype: 'Select',
                    label: 'Available Printers',
                    fieldname: 'selected_printer',
                    options: printers.join('\n'),
                    reqd: true
                }
            ],
            primary_action_label: 'Select',
            primary_action(values) {
                d.hide();
                resolve(values.selected_printer);
            }
        });

        d.show();
    });
}

function print_label(config, zpl_data) {
    return qz.print(config, [{ 
        type: 'raw', 
        format: 'command', 
        data: zpl_data 
    }]);
}

function print_variants(frm) {
    frm.call({
        method: 'frappe.client.get_list',
        args: {
            doctype: 'Item',
            fields: ['name', 'standard_rate', 'price_list'],
            limit_page_length: '500',
            filters: { 'variant_of': frm.doc.name }
        },
        callback: function(r) {
            console.log(r)
            if (Array.isArray(r.message) && r.message.length > 0) {
                qz.websocket.connect().then(() => {
                    return qz.printers.find();
                }).then((printers) => {
                    if (printers.length === 0) {
                        throw new Error('No printers found');
                    }
                    return selectPrinter(printers);
                }).then((selectedPrinter) => {
                    var config = qz.configs.create(selectedPrinter);
                    let printPromises = r.message.map(variant => {
                        let zpl = generate_zpl(variant);
                        return print_label(config, zpl);
                    });
                    return Promise.all(printPromises);
                }).then(() => {
                    frappe.msgprint(__('All print jobs sent successfully.'));
                }).catch((e) => {
                    console.error(e);
                    frappe.msgprint(__('Error: ') + e.message);
                }).finally(() => {
                    qz.websocket.disconnect();
                });
            } else {
                frappe.msgprint(__('No variants to print.'));
            }
        }
    });
}

// Store the default onload function
var default_onload = frappe.listview_settings['Sales Order'].onload;

// Define the custom onload function
function custom_onload(listview) {
    // Call the default onload function
    if (default_onload) {
        default_onload(listview);
    }

    // Add your custom functionality
    listview.page.add_action_item(__('Close Sales Orders'), function() {
        let selected_orders = listview.get_checked_items();
        if (selected_orders.length > 0) {
            frappe.call({
                method: "gspl.doc_events.sales_order.bulk_close_sales_orders",
                args: {
                    sales_orders: selected_orders
                },
                callback: function(r) {
                    if (r.message) {
                        frappe.msgprint(__('Selected Sales Orders have been closed successfully.'));
                        listview.refresh();
                    }
                }
            });
        } else {
            frappe.msgprint(__('Please select at least one Sales Order.'));
        }
    });
}

// Assign the custom onload function to the listview settings
frappe.listview_settings['Sales Order'].onload = custom_onload;

