frappe.ui.form.on('Salary Slip', {
	onload(frm) {
		if (frm.doc.status == 'Draft') {

			var holiday_list;
			var dates = [];
			console.log(frm.doc);
			frappe.call({
				method: 'frappe.client.get_value',
				args: {
					doctype: 'Employee',
					name: frm.doc.employee,
					fieldname: 'holiday_list'
				},
				callback: function(data) {
					holiday_list = data.message.holiday_list
				}

			}).then(() => {
				console.log(holiday_list);
				frappe.db.get_doc(doctype = 'Holiday List', name = holiday_list).then((dat) => {
					var holidays = dat.holidays;
					var i;
					for (i = 0; i < holidays.length; i++) {
						var date = new Date(holidays[i].holiday_date);
						console.log(frappe.datetime.add_days(date, -1));
						if (date >= new Date(frm.doc.start_date) && date <= new Date(frm.doc.end_date)) dates.push(holidays[i].holiday_date);
						//dates = dates.filter(distinct);
					}
					console.log(dates);
				}).then(() => {
					console.log(dates);
					frappe.call({
						method: 'frappe.client.get_list',
						args: {
							doctype: 'Attendance',
							filters: [
								//'employee': frm.doc.employee,
								// 'attendance_date': ['in', dates]
								['employee', '=', frm.doc.employee],
								['attendance_date', 'between', [frm.doc.start_date, frm.doc.end_date]]
							],
							fields: ['employee', 'attendance_date', 'status'],
							limit_page_length: '50'
						},
						callback: function(data) {
							console.log(data);
							var present = 0;
							var absent = 0; //absent on holiday
							var abs = 0; //marked absent
							var holiday = dates.length; //Holiday and holiday taken
							var i
							var unique = data.message
							for (i = 0; i < unique.length; i++) {
								if (dates.includes(unique[i].attendance_date) && unique.indexOf(unique[i]) == i) {
									console.log(i);
									if (unique[i].status == 'Absent') absent += 1;
									else if (unique[i].status == 'Present') present += 1;
									else if (unique[i].status == 'Half Day') present += 0.5;
									else if (unique[i].status == 'Work From Home') present += 1;
									else holiday -= 1;
								} else if (unique[i].status == 'Absent') abs += 1;
							}
							abs = (frm.doc.absent_days - holiday - abs); //unmarked days
							console.log(absent);
							console.log(holiday)
							console.log(abs);
							let earnings = frm.doc.earnings;
							var i;
							var perday = 0;
							var dailywage = 0;
							if (earnings.length > 0) {
								for (i = 0; i < earnings.length; i++) {
									if (earnings[i].salary_component == "Basic") {
										perday = earnings[i].default_amount / frm.doc.total_working_days
										console.log(perday);
										/*if (perday > 450) dailywage = 360
										else if (perday > 300) dailywage = 270
										else dailywage = 180*/
									} else if (earnings[i].salary_component == "Ex gratia") {
										if (present > 0 || abs > 0) {
											console.log(present);
											console.log(dailywage * abs);
											dailywage = 0;
											earnings[i].amount = earnings[i].additional_amount + (perday * present) + (dailywage * abs);
											frm.refresh();
										}
										break;
									}
								}
								if (i == earnings.length && (present > 0)) { // or abs>0
									console.log(present);
									var new_row = frm.add_child('earnings');
									new_row.salary_component = 'Ex gratia';
									dailywage = 0;
									new_row.amount = (perday * present) + (dailywage * abs);
									frm.save();
								} //for non working day ex gratia
							}

							frm.set_value('leave_without_pay', absent)
							//frm.set_value('absent_days',(frm.doc.absent_days + absent))
							//frm.set_value('payment_days',(frm.doc.payment_days - absent))
							frm.save();
						}

					})

				})
			})
		}

	},
	//validate(frm) {
	//    if (frm.is_dirty()) {
	//        frm.trigger('onload').then(() => {
	//            frm.save();
	//        })
	//    }
	//},
	on_submit(frm) {
		if (frm.doc.salary_structure == "Karigar Per Day") {
			var supplier = null
			var karigar_work_name = null
			frappe.call({
				method: 'frappe.client.get_value',
				args: {
					doctype: 'Employee',
					name: frm.doc.employee,
					fieldname: 'supplier'
				},
				callback: function(data) {
					supplier = data.message.supplier
				}

			}).then(() => {
				console.log(supplier)
				frappe.call({
					method: 'frappe.client.get_value',
					args: {
						doctype: 'Supplier',
						filters: {
							'name': supplier,
						},
						fieldname: ['karigar_work_name']
					},
					callback: function(data) {
						console.log(data)
						karigar_work_name = data.message.karigar_work_name
					}

				}).then(() => {
					var items = [];
					items.push({
						item_code: karigar_work_name,
						qty: frm.doc.payment_days,
						rate: frm.doc.gross_pay / frm.doc.payment_days
					});
					frappe.db.insert({
						doctype: 'Purchase Invoice',
						supplier: supplier,
						posting_date: frappe.datetime.get_today(),
						tax_withholding_category: 'TDS - 194C - Individual',
						apply_tds: 1,
						//due_date: frappe.datetime.get_today() + 7,
						update_stock: 0,
						items: items
					}).then(function(doc) {
						console.log("Done!");
						frappe.set_route(['Form', 'Purchase Invoice', doc.name]);
						frm.refresh();
					});
				})
			})
		} else {
			var accounts = [];

			var account_name;
			for (var i = 0; i < frm.doc.earnings.length; i++) {

				if (frm.doc.earnings[i].abbr == 'b') {
					account_name = "Salary - GSPL";
				} else if (frm.doc.earnings[i].abbr == 'exg') {
					account_name = "Exgratia - GSPL";
				} else if (frm.doc.earnings[i].abbr == 'bon') {
					account_name = "Bonus - 4DF";
					if (frm.doc.earnings[i].amount > 0) accounts.push({
						account: "Bonus Payable - 4DF",
						party_type: 'Employee',
						party: frm.doc.employee,
						credit_in_account_currency: frm.doc.earnings[i].amount
					})
				} else break;
				if (frm.doc.earnings[i].amount > 0) accounts.push({
					account: account_name,
					debit_in_account_currency: frm.doc.earnings[i].amount
				})
			}

			for (var i = 0; i < frm.doc.deductions.length; i++) {
				if (frm.doc.deductions[i].abbr == 'PT') {
					account_name = "Professional Tax - GSPL";
				} else if (frm.doc.deductions[i].abbr == 'ESI1') {
					account_name = "ESI Payable - GSPL";
					if (frm.doc.deductions[i].amount > 0) accounts.push({
						account: "ESI - GSPL",
						debit_in_account_currency: frm.doc.deductions[i].amount
					})
				} else if (frm.doc.deductions[i].abbr == 'ESI2') {
					account_name = "ESI Payable - GSPL";
				} else break;
				if (frm.doc.deductions[i].amount > 0) accounts.push({
					account: "ESI - GSPL",
					credit_in_account_currency: frm.doc.deductions[i].amount
				})
			}

